public String processReference(String fullContent, String fromAddress) {
    String tmp = fullContent.replaceAll("\n", "");
    tmp = tmp.replaceAll("\r", "");
    tmp = tmp.replaceAll("\t", " ");

    int startIndex = -1;
    for(String anchor: anchors) {
        Pattern pattern = Pattern.compile(anchor);
        Matcher matcher = pattern.matcher(tmp);
        boolean containsPattern = matcher.find();
        if(containsPattern) {
            int start = matcher.start();
            if(startIndex == -1 || start < startIndex) startIndex = start;
        }
    }
    if(startIndex != -1) {
        int refId = new Random().nextInt(9999);
        String ellipsisDiv = this.generateEllipsisDiv(refId);
        String content = Encoder.sanitizeHTML(tmp.substring(0, startIndex));
        String refDiv = Encoder.sanitizeHTML(tmp.substring(startIndex));
        refDiv = "<div name=\"ref_content_" + refId + "\" style=\"display:none;color:#500050;\">" + refDiv + "</div>";
        fullContent = content + ellipsisDiv + refDiv;
    } else {
        fullContent = Encoder.sanitizeHTML(fullContent);
    }
    return fullContent;
}
